library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity vector_assign is
    Port ( 
        a : in  std_ulogic_vector(3 downto 0);
        b : out std_ulogic_vector(3 downto 0)
    );
end vector_assign;

architecture Behavioral of vector_assign is
begin
    b <= a;
end Behavioral;

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity tb is
end tb;

architecture Behavioral of tb is
    component vector_assign
        Port (
            a : in  std_ulogic_vector(3 downto 0);
            b : out std_ulogic_vector(3 downto 0)
        );
    end component;

    signal a : std_ulogic_vector(3 downto 0) := (others => '0');
    signal b : std_ulogic_vector(3 downto 0);

begin
    uut: vector_assign
        Port map (
            a => a,
            b => b
        );

    stimulus: process
    begin
        a <= "0001";
        wait for 10 ns;
        wait;
    end process;
end Behavioral;
